SELECT TCSS.CARGO_INFO_ID, TCSSD.ID, TCSSD.STORAGE_SETTLE_ID, TCSSD."DATE", TCSSD.TON, TCSSD.BILLABLE_TON, TCSSD.IN_TON, TCSSD.OUT_TON, TCSSD.AMOUNT, TCSSD.TAX_AMOUNT FROM T_COST_STORAGE_SETTLE_DETAIL TCSSD JOIN T_COST_STORAGE_SETTLE TCSS ON TCSSD.STORAGE_SETTLE_ID = TCSS.ID WHERE TCSS.CARGO_INFO_ID IN
