ORDER BY "DATE"

mapper.insert:
BEGIN
INSERT INTO T_COST_STORAGE_AMT_CALC_REC(ID, CARGO_INFO_ID, OVERDUE_DAYS, IS_SETTLEMENT, AMOUNT, FAILED_CODE, FAILED_REMARK,CREATE_TIME,CALC_START_TIME, CALC_END_TIME,FREE_DAYS) VALUES (#{item.id, jdbcType=BIGINT}, #{item.cargoInfoId, jdbcType=BIGINT},#{item.overdueDays, jdbcType=VARCHAR}, #{item.isSettlement, jdbcType=DECIMAL}, #{item.amount, jdbcType=DECIMAL}, #{item.failedCode, jdbcType=VARCHAR}, #{item.failedRemark, jdbcType=VARCHAR}, #{item.createTime, jdbcType=TIMESTAMP},#{item.calcStartTime, jdbcType=TIMESTAMP}, #{item.calcEndTime, jdbcType=TIMESTAMP},#{item.freeDays,jdbcType=VARCHAR});
END;

BEGIN
INSERT INTO storage_demo (id, work_type, CARGO_CATEGORY_NAME, cargo_type_name, cargo_name, source, Flow_direction, in_out_type, trade_type, CARGO_OWNER_NAME, CARGO_OWNER_ID, cargo_info_no, cargo_info_ID, ship_name, scn, is_Clear, free_days, cal_start_time, cal_END_time, over_date, over_time, cargo_info_time, COMPANY_NAME, amount, remark,SETTLE_STATUS,CREATE_TIME ) VALUES ( #{item.id}, #{item.workType}, #{item.cargoCategoryName}, #{item.cargoTypeName}, #{item.cargoName}, #{item.source}, #{item.flowDirection}, #{item.inOutType}, #{item.tradeType}, #{item.cargoOwnerName}, #{item.cargoOwnerId}, #{item.cargoInfoNo}, #{item.cargoInfoId}, #{item.shipName}, #{item.scn}, #{item.isClear}, #{item.freeDays}, #{item.calStartTime}, #{item.calEndTime}, #{item.overDate}, #{item.overDays}, #{item.cargoInfoTime}, #{item.companyName}, #{item.amount}, #{item.remark}, #{item.settleStatus}, #{item.createTime} );
END;

mapper.select:
select SD.ID, SD.WORK_TYPE, SD.CARGO_CATEGORY_NAME, SD.CARGO_TYPE_NAME, SD.CARGO_NAME, SD.SOURCE, SD.FLOW_DIRECTION, SD.IN_OUT_TYPE, SD.TRADE_TYPE, SD.CARGO_OWNER_NAME, SD.CARGO_OWNER_ID, SD.CARGO_INFO_NO, SD.CARGO_INFO_ID, SD.SHIP_NAME, SD.SCN, SD.IS_CLEAR, SD.FREE_DAYS, SD.CAL_START_TIME, SD.CAL_END_TIME, SD.OVER_DATE, SD.OVER_TIME, case when SD.over_TIMe >0 then '1' else '0' end is_over_time, SD.CARGO_INFO_TIME, SD.COMPANY_NAME, SD.AMOUNT, SD.REMARK, SD.CREATE_TIME, SD.SETTLE_STATUS from STORAGE_DEMO SD join (select CARGO_INFO_ID,max(CREATE_TIME) CREATE_TIME from STORAGE_DEMO group by CARGO_INFO_ID) tmp on tmp.CARGO_INFO_ID = SD.CARGO_INFO_ID and tmp.CREATE_TIME = SD.CREATE_TIME where 1=1
and sd.ship_name like #{shipName_like}
and sd.cargo_info_no like #{cargoInfoNo_like}
and SD.CARGO_NAME like #{cargoName_like}
and SD.flow_Direction like #{flowDirection_like}
and sd.CARGO_OWNER_ID = #{cargoOwnerId}
and sd.settle_Status = #{settleStatus}
and case when SD.over_TIMe >0 then '1' else '0' end = #{isOverTime}
and sd.is_Clear = #{isClear}
and sd.work_Type = #{workType}
and (sd.cargo_info_time >= #{beginDate} and sd.cargo_info_time <= #{endDate} )
